('business:6-1-ethical-environmental:fib:a1d90211', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'fib', 'fib', 2, '{"question": "To combat climate _____, businesses are trying to reduce their carbon _____ by using electric vehicles.", "blankOptions": {"B1": ["waste", "landfill", "change", "costs"], "B2": ["renewable", "emissions", "labour", "reputation"]}}'::jsonb, '{"blanks": {"B1": "change", "B2": "emissions"}}'::jsonb),
