('business:6-1-ethical-environmental:match:9d30e88e', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ethics”?", "options": ["The unethical use of young children below the legal age for cheap employment.", "Focusing on what is the ''right'' or ''wrong'' thing to do in business.", "A movement encouraging a fair price to be paid to suppliers in developing countries.", "Manufacturing methods that do not lead to the depletion of natural resources."]}'::jsonb, '{"answer": 1, "explain": "“Ethics” means: Focusing on what is the ''right'' or ''wrong'' thing to do in business."}'::jsonb),
('business:6-1-ethical-environmental:match:1be43669', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Child Labour”?", "options": ["A movement encouraging a fair price to be paid to suppliers in developing countries.", "Manufacturing methods that do not lead to the depletion of natural resources.", "The unethical use of young children below the legal age for cheap employment.", "Resources that can be used more than once, such as wind or solar power."]}'::jsonb, '{"answer": 2, "explain": "“Child Labour” means: The unethical use of young children below the legal age for cheap employment."}'::jsonb),
('business:6-1-ethical-environmental:match:7ec0769f', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fairtrade”?", "options": ["Manufacturing methods that do not lead to the depletion of natural resources.", "Resources that can be used more than once, such as wind or solar power.", "Resources that can only be used once and will run out, like oil and coal.", "A movement encouraging a fair price to be paid to suppliers in developing countries."]}'::jsonb, '{"answer": 3, "explain": "“Fairtrade” means: A movement encouraging a fair price to be paid to suppliers in developing countries."}'::jsonb),
('business:6-1-ethical-environmental:match:c873844b', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sustainable Production”?", "options": ["Resources that can be used more than once, such as wind or solar power.", "Resources that can only be used once and will run out, like oil and coal.", "Acting to make production sustainable and reduce damage to the planet.", "Manufacturing methods that do not lead to the depletion of natural resources."]}'::jsonb, '{"answer": 3, "explain": "“Sustainable Production” means: Manufacturing methods that do not lead to the depletion of natural resources."}'::jsonb),
('business:6-1-ethical-environmental:match:555827a4', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Renewable Resources”?", "options": ["Resources that can only be used once and will run out, like oil and coal.", "Resources that can be used more than once, such as wind or solar power.", "Acting to make production sustainable and reduce damage to the planet.", "Environmental damage to air, water, or land caused by manufacturing or transport."]}'::jsonb, '{"answer": 1, "explain": "“Renewable Resources” means: Resources that can be used more than once, such as wind or solar power."}'::jsonb),
('business:6-1-ethical-environmental:match:b1c95c4b', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Non-renewable Resources”?", "options": ["Acting to make production sustainable and reduce damage to the planet.", "Resources that can only be used once and will run out, like oil and coal.", "Environmental damage to air, water, or land caused by manufacturing or transport.", "The environmental consideration of how a business recycles or safely discards its rubbish."]}'::jsonb, '{"answer": 1, "explain": "“Non-renewable Resources” means: Resources that can only be used once and will run out, like oil and coal."}'::jsonb),
('business:6-1-ethical-environmental:match:77172ad6', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Environmentally Friendly”?", "options": ["Environmental damage to air, water, or land caused by manufacturing or transport.", "Acting to make production sustainable and reduce damage to the planet.", "The environmental consideration of how a business recycles or safely discards its rubbish.", "How the public views a business; this improves significantly when a business acts ethically."]}'::jsonb, '{"answer": 1, "explain": "“Environmentally Friendly” means: Acting to make production sustainable and reduce damage to the planet."}'::jsonb),
('business:6-1-ethical-environmental:match:18ed085a', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Pollution”?", "options": ["The environmental consideration of how a business recycles or safely discards its rubbish.", "How the public views a business; this improves significantly when a business acts ethically.", "The main financial disadvantage of choosing to source Fairtrade materials or install green technology.", "Environmental damage to air, water, or land caused by manufacturing or transport."]}'::jsonb, '{"answer": 3, "explain": "“Pollution” means: Environmental damage to air, water, or land caused by manufacturing or transport."}'::jsonb),
('business:6-1-ethical-environmental:match:fa41e71a', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Waste Disposal”?", "options": ["The environmental consideration of how a business recycles or safely discards its rubbish.", "How the public views a business; this improves significantly when a business acts ethically.", "The main financial disadvantage of choosing to source Fairtrade materials or install green technology.", "An ethical consideration involving paying bills on time and offering fair prices."]}'::jsonb, '{"answer": 0, "explain": "“Waste Disposal” means: The environmental consideration of how a business recycles or safely discards its rubbish."}'::jsonb),
('business:6-1-ethical-environmental:match:ad0b0b60', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reputation”?", "options": ["How the public views a business; this improves significantly when a business acts ethically.", "The main financial disadvantage of choosing to source Fairtrade materials or install green technology.", "An ethical consideration involving paying bills on time and offering fair prices.", "Focusing on what is the ''right'' or ''wrong'' thing to do in business."]}'::jsonb, '{"answer": 0, "explain": "“Reputation” means: How the public views a business; this improves significantly when a business acts ethically."}'::jsonb),
('business:6-1-ethical-environmental:match:7d38ae7c', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Higher Costs”?", "options": ["The main financial disadvantage of choosing to source Fairtrade materials or install green technology.", "An ethical consideration involving paying bills on time and offering fair prices.", "Focusing on what is the ''right'' or ''wrong'' thing to do in business.", "The unethical use of young children below the legal age for cheap employment."]}'::jsonb, '{"answer": 0, "explain": "“Higher Costs” means: The main financial disadvantage of choosing to source Fairtrade materials or install green technology."}'::jsonb),
('business:6-1-ethical-environmental:match:4fe6ab63', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Treatment of Suppliers”?", "options": ["Focusing on what is the ''right'' or ''wrong'' thing to do in business.", "An ethical consideration involving paying bills on time and offering fair prices.", "The unethical use of young children below the legal age for cheap employment.", "A movement encouraging a fair price to be paid to suppliers in developing countries."]}'::jsonb, '{"answer": 1, "explain": "“Treatment of Suppliers” means: An ethical consideration involving paying bills on time and offering fair prices."}'::jsonb),
('business:6-2-the-economic-climate:exam:95892d41', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Which one of the following actions should the car dealership take to help increase its sales during a period of falling consumer income?", "options": ["A — Advertise less", "B — Offer price reductions", "C — Reduce customer engagement", "D — Reduce its costs"], "caseStudy": "Falling levels of consumer income have caused a car dealership to experience a significant reduction in retail sales.", "hint": "Think about what happens when customers have less money. What marketing action directly makes products more affordable and attractive to price-sensitive buyers?", "starter": "The correct answer is..."}'::jsonb, '{"markScheme": "<div class=\"marks-section\">\n  <h5>Answer: B — Offer price reductions</h5>\n  <p><strong>Why B is correct:</strong> When consumer incomes fall, customers have less money to spend. Offering price reductions makes the cars more accessible to buyers with reduced budgets, directly addressing the affordability problem and helping to maintain demand.</p>\n  <br>\n  <p><strong>Why the other options are wrong:</strong></p>\n  <ul>\n    <li><strong>A — Advertise less:</strong> Reducing advertising would make the business less visible to potential customers, likely causing sales to fall further — the opposite of what is needed.</li>\n    <li><strong>C — Reduce customer engagement:</strong> Poor customer engagement means fewer interactions with potential buyers, reducing the chance of making a sale. This would worsen the problem.</li>\n    <li><strong>D — Reduce its costs:</strong> While reducing costs is a sensible internal strategy during a downturn, it does not directly increase sales. The question asks what should be done to increase sales, not to manage internal finances.</li>\n  </ul>\n</div>", "modelAnswer": "B — Offer price reductions."}'::jsonb),
('business:6-2-the-economic-climate:exam:67a58fa2', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'exam', 'mcq', 1, '{"num": "Textbook Q1 (Knowledge)", "question": "Which of the following statements is true?", "options": ["A — The sales of a business will always increase when incomes rise", "B — Rising incomes often lead to an increase in the sales of luxury goods", "C — A rise in unemployment will make all consumers worse off", "D — A fall in consumer income will always cause a business to sell less"], "caseStudy": "JC Motors Ltd have been trading for 20 years. They specialise in selling high-end bespoke cars that start from £50,000 and can be as expensive as £300,000. Owing to the recent downturn in the economy that has led to falling consumer incomes and an increase in unemployment from 2 million to 2.2 million people, they have started to diversify and have a small range of second hand cars on sale that start at £15,000 and go up to £80,000.", "hint": "Watch out for the words ''always'' and ''all'' — these are clues that a statement is likely to be FALSE. Think about which statement is sometimes true and not an absolute rule.", "starter": "The correct answer is..."}'::jsonb, '{"markScheme": "<div class=\"marks-section\">\n  <h5>Answer: B — Rising incomes often lead to an increase in the sales of luxury goods</h5>\n  <p><strong>Why B is correct:</strong> When incomes rise, customers can afford higher-quality and non-essential items. Luxury goods businesses like JC Motors typically benefit from rising incomes, as more customers can consider purchasing high-end products. The word ''often'' makes this statement accurate — it is a tendency, not an absolute rule.</p>\n  <br>\n  <p><strong>Why the other options are wrong:</strong></p>\n  <ul>\n    <li><strong>A — \"Will always increase\":</strong> FALSE. Businesses selling cheap or budget goods may actually see sales FALL when incomes rise, as customers trade up to more expensive alternatives.</li>\n    <li><strong>C — \"Will make ALL consumers worse off\":</strong> FALSE. Not all consumers are unemployed. Those who keep their jobs may even benefit if lower unemployment causes wages to eventually rise. Budget shoppers may also find it easier to get work.</li>\n    <li><strong>D — \"Will always cause a business to sell less\":</strong> FALSE. Discount retailers like Aldi can see sales RISE when consumer incomes fall, as customers switch to cheaper options.</li>\n  </ul>\n</div>", "modelAnswer": "B — Rising incomes often lead to an increase in the sales of luxury goods."}'::jsonb),
('business:6-2-the-economic-climate:mcq:c09f5a6d', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "What does the term ''economic climate'' refer to?", "options": ["The weather conditions affecting a country''s agriculture", "How well the country is doing in terms of income and employment levels", "The level of inflation in the economy", "The number of businesses trading in a country"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. The economic climate refers to how well the country is doing in terms of the levels of income and employment. It does NOT refer to weather or climate change — a common examiner-noted mistake."}'::jsonb),
('business:6-2-the-economic-climate:mcq:85d099c0', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "Consumer spending is most likely to fall when:", "options": ["Average incomes rise", "Unemployment falls", "The country produces less as measured by GDP", "Immigration rises"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. When GDP falls (a recession), incomes and employment also fall, reducing consumer spending. Rising incomes (A) and falling unemployment (B) both increase spending. Immigration (D) is not directly linked."}'::jsonb),
('business:6-2-the-economic-climate:mcq:9cb53c21', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "In a period of rising income and employment, most businesses can expect:", "options": ["Prices to fall", "Sales to rise", "Profits to fall", "Immigration to fall"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. When incomes rise, customers have more to spend, so demand increases and sales rise. Prices typically rise (not fall) in a growing economy, and profits usually increase too."}'::jsonb),
('business:6-2-the-economic-climate:mcq:d8daed93', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "When a business loses sales due to a fall in consumer income, it should:", "options": ["Increase the amount it produces", "Stop selling the product abroad", "Reduce production costs", "Recruit more workers"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Reducing production costs allows the business to lower prices or maintain profit margins despite falling sales. Increasing production (A) or recruiting more workers (D) would be counterproductive when demand is falling."}'::jsonb),
('business:6-2-the-economic-climate:mcq:d8a4189c', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "A tour company has average annual sales of £8 million. When income falls by 2%, its sales fall by 4%. What is the expected fall in sales if income fell by 2%?", "options": ["£80,000", "£160,000", "£320,000", "£640,000"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. A 4% fall on £8 million = £8,000,000 × 0.04 = £320,000. Option A (£80,000) is 1% of £8m. Option B (£160,000) is 2% of £8m. Option D (£640,000) is 8% of £8m."}'::jsonb),
('business:6-2-the-economic-climate:mcq:dadc7cac', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "Which of the following is most likely to benefit from a fall in consumer incomes?", "options": ["A luxury car dealership", "A five-star hotel chain", "A budget supermarket selling own-label products", "A high-end bespoke kitchen manufacturer"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. When incomes fall, consumers trade down to cheaper alternatives, benefiting discount retailers. Luxury and high-end businesses (A, B, D) suffer as consumers can no longer afford their products."}'::jsonb),
('business:6-2-the-economic-climate:mcq:bee293f6', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "What is the most likely impact of falling unemployment on a business''s production costs?", "options": ["Costs will fall because there are fewer workers to pay", "Costs will rise because wages increase due to competition for workers", "Costs will remain unchanged", "Costs will fall because workers become more productive"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. When unemployment falls, fewer workers are available, creating competition for labour. Businesses must offer higher wages to attract and retain staff, raising their production costs."}'::jsonb),
('business:6-2-the-economic-climate:mcq:74083960', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "What is a recession?", "options": ["A period when GDP is rising", "A period when unemployment is at its lowest", "A period when GDP is falling, causing income and employment to fall", "A period when consumer prices are rising"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. A recession is defined as a period when GDP is falling, which causes income to fall and unemployment to rise. Option A describes economic growth. Option D describes inflation."}'::jsonb),
('business:6-2-the-economic-climate:mcq:a94b3906', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "Falling levels of consumer income have caused a car dealership to experience a significant reduction in retail sales. Which action should the dealership take?", "options": ["Advertise less", "Offer price reductions", "Reduce customer engagement", "Reduce its costs only"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Offering price reductions makes the cars more affordable during a period of lower consumer income, helping to maintain sales. Advertising less (A) or reducing customer engagement (C) would further harm sales."}'::jsonb),
('business:6-2-the-economic-climate:mcq:ae3732d8', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "Which of the following statements about the impact of rising income is TRUE?", "options": ["The sales of all businesses will always increase when incomes rise", "Rising incomes often lead to an increase in sales of luxury goods", "A rise in unemployment will make all consumers worse off", "A fall in consumer income will always cause a business to sell less"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Rising incomes often boost luxury goods sales because consumers can now afford higher-quality or non-essential items. ''Always'' in options A, C and D is incorrect — there are always exceptions (e.g. budget goods may see falls when incomes rise)."}'::jsonb),
('business:6-2-the-economic-climate:mcq:53422940', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "What does GDP stand for and what does it measure?", "options": ["General Domestic Price — the average cost of goods in a country", "Gross Domestic Product — a measure of how much a country produces in a year", "Government Debt Percentage — the level of public borrowing", "Gross Disposable Pay — the average take-home wage"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. GDP (Gross Domestic Product) measures the total value of goods and services a country produces in a year. It is the key indicator of economic growth or recession."}'::jsonb),
('business:6-2-the-economic-climate:mcq:c40fb9a1', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT an example of a business strategy used during a recession?", "options": ["Reducing waste in production", "Increasing advertising to boost sales", "Hiring more full-time workers to increase output", "Taking out cheaper loans to reduce interest costs"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. During a recession, businesses typically try to reduce costs — hiring more full-time workers increases the wage bill, which is the opposite of what most businesses do in a downturn. All other options are common recession strategies."}'::jsonb),
('business:6-2-the-economic-climate:tf:2da115d6', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "The economic climate only refers to weather and environmental conditions affecting businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. The economic climate refers to how well the country is doing in terms of income and employment levels — NOT the weather. This is one of the most common misconceptions noted by examiners."}'::jsonb),
('business:6-2-the-economic-climate:tf:f8b98a4b', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "When consumer incomes rise, the sales of ALL businesses will increase."}'::jsonb, '{"answer": false, "explain": "FALSE. While most businesses benefit from rising incomes, businesses selling cheap or lower-quality products may actually see sales FALL as customers switch to more expensive alternatives they can now afford."}'::jsonb),
('business:6-2-the-economic-climate:tf:dadae6d5', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "A recession is a period when GDP is falling, causing income and employment to fall."}'::jsonb, '{"answer": true, "explain": "TRUE. This is the official definition. During a recession, GDP falls, businesses cut production, workers are laid off, unemployment rises, and incomes fall — reducing consumer spending further."}'::jsonb),
('business:6-2-the-economic-climate:tf:f7608290', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "When unemployment falls, businesses will find it easier and cheaper to hire new workers."}'::jsonb, '{"answer": false, "explain": "FALSE. When unemployment falls, fewer workers are available. This makes it HARDER to recruit, and businesses often need to offer HIGHER wages to attract staff — increasing their costs."}'::jsonb),
('business:6-2-the-economic-climate:tf:3c009cbd', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "A fall in consumer income always causes a business to sell less."}'::jsonb, '{"answer": false, "explain": "FALSE. Some businesses actually benefit from falling incomes. Discount retailers like Aldi saw sales and market share GROW during the 2008 recession as consumers switched to cheaper options."}'::jsonb),
('business:6-2-the-economic-climate:tf:ed607863', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "Aldi''s rapid growth after 2008 was partly due to the poor economic climate."}'::jsonb, '{"answer": true, "explain": "TRUE. As consumer incomes fell after the 2008 recession, shoppers switched to cheaper options. Aldi''s low-price model was perfectly positioned to benefit, growing its market share from 2.5% to 7.8% by 2020."}'::jsonb),
('business:6-2-the-economic-climate:tf:3f9ce328', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "GDP (Gross Domestic Product) is a measure of how much a country produces in a year."}'::jsonb, '{"answer": true, "explain": "TRUE. GDP measures the total value of goods and services produced by a country in a year. It is the main indicator of economic growth or recession."}'::jsonb),
('business:6-2-the-economic-climate:tf:71c6919a', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "During a recession, all businesses will lose money and many will close."}'::jsonb, '{"answer": false, "explain": "FALSE. While many businesses struggle in a recession, some thrive. Budget retailers, discount stores, and businesses that adapt effectively can grow during a downturn. Carpet Right survived the 2008 recession; Comet did not."}'::jsonb),
('business:6-2-the-economic-climate:tf:f06bd9df', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "The international economic climate can affect UK businesses even if the UK economy itself is performing well."}'::jsonb, '{"answer": true, "explain": "TRUE. If major trading partners (such as the EU or USA) go into recession, demand for UK exports falls. The 2008 recession affected the UK AND its trading partners simultaneously."}'::jsonb),
('business:6-2-the-economic-climate:tf:646af571', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "When unemployment rises, businesses will typically face higher wage costs."}'::jsonb, '{"answer": false, "explain": "FALSE. When unemployment RISES, there are MORE workers looking for jobs. This gives businesses more choice and reduces competition for labour, often allowing businesses to pay LOWER wages, reducing their costs."}'::jsonb),
('business:6-2-the-economic-climate:tf:259b9af1', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "The distribution of income refers to how evenly income is shared among people in the community."}'::jsonb, '{"answer": true, "explain": "TRUE. Distribution of income describes the gap between rich and poor. In the UK since the 1980s, this gap has widened — the rich have seen incomes rise faster than lower earners."}'::jsonb),
('business:6-2-the-economic-climate:tf:c3cd20ea', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tf', 'tf', 1, '{"question": "Comet and Carpet Right were both affected equally by the 2008 recession, and both eventually closed."}'::jsonb, '{"answer": false, "explain": "FALSE. Both were affected by the recession, but only Comet closed (by December 2012). Carpet Right adapted — it moved upmarket, improved customer service, closed some stores, and offered interest-free credit. It survived and grew."}'::jsonb),
('business:6-2-the-economic-climate:learn:8142239c', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Learn and memorise these official definitions — they are the foundation of every answer you write in this topic.</p>\n<ul>\n  <li><strong>Economic climate:</strong> Refers to how well the country is doing in terms of the levels of income and employment.</li>\n  <li><strong>Income:</strong> The amount of money that people receive from work and from assets they own, such as shares and property.</li>\n  <li><strong>Customers:</strong> Buyers who buy goods and services for the satisfaction or benefit they will get from them.</li>\n  <li><strong>Consumer income:</strong> The total amount of income that all customers in the country receive and which they have available to spend.</li>\n  <li><strong>Level of employment:</strong> The number of people in work in a country.</li>\n  <li><strong>Level of unemployment:</strong> The number of people out of work in a country.</li>\n  <li><strong>Level of income:</strong> The average income of people in a country.</li>\n  <li><strong>GDP (Gross Domestic Product):</strong> A measure of how much a country produces in a year. It influences the level of income and employment.</li>\n  <li><strong>Economic growth:</strong> A period when GDP is rising, causing income and employment to rise.</li>\n  <li><strong>Recession:</strong> A period when GDP is falling, causing income and employment to fall.</li>\n  <li><strong>Distribution of income:</strong> Refers to how the income is shared out among different people in the community. It can become more unequal if the incomes of the rich rise faster than those of lower earners.</li>\n  <li><strong>International economic climate:</strong> Refers to what is happening to income and employment in different parts of the world.</li>\n</ul>", "question": "According to the key definitions, what does ''recession'' mean?", "options": ["A period when GDP is falling, causing income and employment to fall", "A period when GDP is rising, causing income and employment to rise", "The number of people out of work at any given moment in time", "The average income earned by people living in a country"]}'::jsonb, '{"answer": 0, "explain": "The card defines recession as a period when GDP is falling, causing income and employment to fall — the opposite of economic growth."}'::jsonb),
('business:6-2-the-economic-climate:learn:25e9972d', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "What Is the Economic Climate?", "reading": "<p>The <strong>economic climate</strong> refers to the state of the economy a business operates in. It can be:</p>\n<ul>\n  <li><strong>Favourable</strong> — good for business (rising incomes, low unemployment, growing GDP)</li>\n  <li><strong>Unfavourable</strong> — bad for business (falling incomes, high unemployment, recession)</li>\n</ul>\n<p>⚠️ A favourable climate for one business is <strong>not always</strong> favourable for another. For example, a recession is bad for luxury car dealers but can be good for discount supermarkets like Aldi.</p>\n<br>\n<p>The two main factors you need to know for OCR GCSE are:</p>\n<ul>\n  <li><strong>Changes in consumer income</strong></li>\n  <li><strong>Changes in employment / unemployment levels</strong></li>\n</ul>", "question": "According to this card, is a recession always bad for every business?", "options": ["Yes — a recession is always equally bad for every type of business", "No — a recession can be good for discount supermarkets like Aldi", "Yes — a recession only ever affects large multinational businesses", "No — a recession only ever affects businesses selling luxury goods"]}'::jsonb, '{"answer": 1, "explain": "The card explains a recession is bad for luxury car dealers but can be good for discount supermarkets like Aldi — a favourable/unfavourable climate is not universal."}'::jsonb),
('business:6-2-the-economic-climate:learn:427af540', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "The Impact of Changes in Income", "reading": "<p>Income levels directly affect how much customers can spend, which in turn affects business sales and profits.</p>\n<br>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">📈 When Income RISES</div>\n    <div class=\"pro-item\"><strong>More spending:</strong> Customers have more money so demand for goods and services increases.</div>\n    <div class=\"pro-item\"><strong>Higher revenue & profit:</strong> Businesses can sell more — or even raise prices.</div>\n    <div class=\"pro-item\"><strong>Business expansion:</strong> Firms may need to hire more staff, buy more stock, or open new outlets.</div>\n    <div class=\"pro-item\"><strong>Exception — cheap goods:</strong> Some lower-quality businesses may see sales fall as customers switch to better products they can now afford.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">📉 When Income FALLS</div>\n    <div class=\"con-item\"><strong>Less spending:</strong> Customers have less disposable income, reducing demand.</div>\n    <div class=\"con-item\"><strong>Lower revenue & profit:</strong> Luxury or non-essential businesses are hit hardest.</div>\n    <div class=\"con-item\"><strong>Risk of closure:</strong> Businesses that cannot adapt may close (e.g. Comet in 2012).</div>\n    <div class=\"con-item\"><strong>Exception — budget goods:</strong> Discount businesses like Aldi can actually benefit when incomes fall as customers trade down.</div>\n  </div>\n</div>\n<br>\n<p><strong>How much a business is affected depends on:</strong></p>\n<ul>\n  <li>How much income changes — bigger change = bigger impact</li>\n  <li>The type of product sold — luxury goods are more vulnerable than essentials</li>\n  <li>How other businesses respond — competitors may gain market share</li>\n  <li>How the business itself responds — good businesses adapt and survive</li>\n</ul>", "question": "According to this card, which businesses can benefit when consumer income falls?", "options": ["Luxury car dealers, since falling income increases demand for luxury goods", "Every type of business equally, regardless of what they sell", "Discount businesses like Aldi, as customers trade down to cheaper options", "Only businesses that raise their prices in response to falling income"]}'::jsonb, '{"answer": 2, "explain": "The card lists discount businesses like Aldi as an exception — they benefit when incomes fall as customers trade down, unlike luxury or non-essential businesses."}'::jsonb),
('business:6-2-the-economic-climate:learn:a4ff2411', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "The Impact of Changes in Employment", "reading": "<p>Employment and income are closely linked — when more people are in work, incomes tend to rise, and vice versa. But changes in employment also affect <strong>production costs</strong> and <strong>recruitment</strong>.</p>\n<br>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">📉 When Unemployment RISES (Employment Falls)</div>\n    <div class=\"pro-item\"><strong>Easier to recruit:</strong> More workers are available, giving businesses a larger pool to choose from.</div>\n    <div class=\"pro-item\"><strong>Lower wages:</strong> Greater competition for jobs means businesses may pay less, reducing labour costs.</div>\n    <div class=\"con-item\"><strong>Lower consumer spending:</strong> More unemployed people means less income in the economy, reducing demand for goods.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">📈 When Unemployment FALLS (Employment Rises)</div>\n    <div class=\"pro-item\"><strong>More consumer spending:</strong> More people in work = higher incomes = more demand for goods and services.</div>\n    <div class=\"con-item\"><strong>Harder to recruit:</strong> Fewer workers available; businesses may struggle to find staff with the right skills.</div>\n    <div class=\"con-item\"><strong>Higher wages:</strong> Competition for workers forces businesses to offer higher pay, raising costs and reducing profits.</div>\n  </div>\n</div>\n<br>\n<p><strong>How much a business is affected depends on:</strong></p>\n<ul>\n  <li>How much employment changes</li>\n  <li>The type of employment — a rise in demand for <em>skilled</em> workers is harder to deal with than a rise in demand for unskilled workers</li>\n</ul>", "question": "According to this card, what happens to wages when unemployment rises?", "options": ["Wages tend to rise, since businesses have to compete harder for scarce workers", "Wages stay exactly the same regardless of the unemployment rate", "Wages can only be affected by consumer income, not by employment", "Wages tend to fall, since greater competition for jobs reduces labour costs"]}'::jsonb, '{"answer": 3, "explain": "The card explains that when unemployment rises, greater competition for jobs means businesses may pay less, reducing labour costs."}'::jsonb),
('business:6-2-the-economic-climate:learn:4efcfa3d', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Business Strategies When Income & Employment Fall", "reading": "<p>When the economic climate becomes unfavourable, businesses across all departments must respond strategically to survive. Here are the key strategies by department:</p>\n<br>\n<ul>\n  <li>🏭 <strong>Production:</strong>\n    <ul>\n      <li>Reduce waste to cut costs per unit</li>\n      <li>Improve worker productivity (e.g. new technology)</li>\n      <li>Outsource production to cheaper locations</li>\n    </ul>\n  </li>\n  <br>\n  <li>👥 <strong>Human Resources (HR):</strong>\n    <ul>\n      <li>Motivate workers with bonuses or awards to improve productivity</li>\n      <li>Lay off workers to reduce the wage bill</li>\n      <li>Improve skills through training</li>\n    </ul>\n  </li>\n  <br>\n  <li>📣 <strong>Marketing:</strong>\n    <ul>\n      <li>Increase or improve advertising to attract customers</li>\n      <li>Produce a cheaper product to appeal to lower-income consumers</li>\n      <li>Lower prices to increase demand</li>\n      <li>Target new markets (e.g. sell abroad)</li>\n      <li>Change the product upmarket to appeal to wealthier buyers</li>\n    </ul>\n  </li>\n  <br>\n  <li>💰 <strong>Finance:</strong>\n    <ul>\n      <li>Take out cheaper loans to reduce interest payments</li>\n      <li>Reduce overdraft to save on interest costs</li>\n      <li>Improve cash flow management</li>\n    </ul>\n  </li>\n</ul>", "question": "According to this card, which strategy is listed under the Finance department?", "options": ["Taking out cheaper loans to reduce interest payments", "Increasing or improving advertising to attract more customers", "Laying off workers to reduce the overall wage bill", "Outsourcing production to cheaper locations abroad"]}'::jsonb, '{"answer": 0, "explain": "The card lists taking out cheaper loans under Finance strategies; advertising is Marketing, laying off workers is HR, and outsourcing is Production."}'::jsonb),
('business:6-2-the-economic-climate:learn:40396be8', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Distribution of Income & the International Economic Climate", "reading": "<p>Two additional aspects of the economic climate that can affect businesses are:</p>\n<br>\n<p><strong>📊 Distribution of Income</strong></p>\n<p>Even if the overall level of income stays the same, how income is <em>shared</em> among people matters.</p>\n<ul>\n  <li>Since the 1980s, the gap between rich and poor in the UK has <strong>widened</strong>.</li>\n  <li>If richer people''s incomes rise faster, businesses selling luxury goods may still perform well even during a wider recession.</li>\n  <li>After the 2008 recession, many new jobs were part-time or zero-hours contracts — so income for many rose only slowly, even as employment recovered.</li>\n</ul>\n<br>\n<p><strong>🌍 International Economic Climate</strong></p>\n<p>The UK does not operate in isolation — global economic conditions affect UK businesses too.</p>\n<ul>\n  <li>A world recession or recession in key trading partners (e.g. EU, USA) reduces demand for UK exports.</li>\n  <li>The 2008–09 recession affected both the UK and its trading partners simultaneously.</li>\n  <li>The COVID-19 pandemic in 2020–21 dramatically reduced international trade and travel.</li>\n  <li>Events like Brexit can also affect UK businesses trading internationally.</li>\n</ul>", "question": "According to this card, what has happened to the distribution of income in the UK since the 1980s?", "options": ["The gap between rich and poor has completely disappeared", "The gap between rich and poor in the UK has steadily widened over time", "Income has become perfectly equally distributed among all people", "The government abolished income distribution as an economic measure"]}'::jsonb, '{"answer": 1, "explain": "The card states that since the 1980s the gap between rich and poor in the UK has widened, affecting which businesses perform well during a recession."}'::jsonb),
('business:6-2-the-economic-climate:learn:fe6fbe50', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Comet vs Carpet Right", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Comet vs Carpet Right — Two Very Different Responses to Recession</h4>\n  <p>Both Comet (electrical goods) and Carpet Right (carpets) were successful high-street chains before the 2008 recession. Both sold ''big ticket'' items — expensive purchases that consumers cut back on when incomes fell.</p>\n  <br>\n  <p><strong>Comet</strong> failed to adapt to the downturn. By December 2012, it had closed entirely.</p>\n  <br>\n  <p><strong>Carpet Right</strong> responded by:</p>\n  <ul>\n    <li>Selling better-quality, more expensive carpets (moving upmarket)</li>\n    <li>Improving customer service</li>\n    <li>Closing some stores to reduce costs</li>\n    <li>Offering interest-free credit to attract cautious buyers</li>\n  </ul>\n  <br>\n  <p>By 2016, Carpet Right''s profits had risen by 33.1% and like-for-like sales had grown by 4.8%. It was taken over by Meditor in 2019 and continues to trade.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> The same difficult economic climate affected both businesses equally — but only one survived. The key difference was <strong>how each business responded</strong>. Businesses that adapt their strategy (product, price, promotion, place) can survive and even grow through a recession.</p>", "question": "According to this case study, what was the key difference between Comet and Carpet Right?", "options": ["Comet adapted its strategy, while Carpet Right failed to adapt and closed", "Both businesses closed permanently during the 2008 recession", "Carpet Right adapted its strategy, while Comet failed to adapt and closed", "Neither business was affected at all by the 2008 recession"]}'::jsonb, '{"answer": 2, "explain": "The card explains Carpet Right adapted (moving upmarket, improving service, offering credit) and survived, while Comet failed to adapt and closed by 2012."}'::jsonb),
('business:6-2-the-economic-climate:learn:70650f1c', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Aldi — Turning Recession Into Opportunity", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Aldi — Growing Through the Downturn</h4>\n  <p>In 2007, Aldi held just a <strong>2.5% share</strong> of the UK supermarket market. By 2020, it had become the <strong>sixth-largest supermarket chain</strong> in the UK with a 7.8% market share. Its rapid growth was driven largely by the poor economic climate after 2008.</p>\n  <br>\n  <p>Aldi''s strategy included:</p>\n  <ul>\n    <li>Selling cheaper groceries — some products 50% cheaper than rivals</li>\n    <li>Focusing on own-label products to keep buying costs low</li>\n    <li>A ''no frills'' store experience — basic layout, no saunas or cafés</li>\n    <li>Highly efficient warehousing and distribution to keep costs minimal</li>\n  </ul>\n  <br>\n  <p>During the COVID-19 lockdowns (2020–21), Aldi''s market share temporarily fell as it lacked online services. However, once restrictions lifted, its share rose again.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> A poor economic climate is not bad for every business. Aldi proves that a business model built around <strong>low cost and low price</strong> can turn an economic downturn into a competitive advantage. When consumer incomes fall, customers trade down — and discount retailers benefit directly.</p>", "question": "According to the Aldi case study, what has driven its rapid growth since 2008?", "options": ["A strong economic climate, as customers had more money to spend", "Aldi''s decision to become the most expensive supermarket in the whole UK", "Aldi''s decision to add saunas and cafés to every one of its stores", "The poor economic climate, as customers traded down to cheaper groceries"]}'::jsonb, '{"answer": 3, "explain": "The card explains Aldi''s growth was driven largely by the poor economic climate after 2008, as customers traded down to its cheaper ''no frills'' groceries."}'::jsonb),
('business:6-2-the-economic-climate:learn:aa6b1e8c', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: The Coronavirus Pandemic (2020–21)", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: COVID-19 — The Biggest Fall in UK GDP Ever Recorded</h4>\n  <p>The coronavirus pandemic caused the largest drop in UK GDP ever recorded — by March 2021, GDP was <strong>8.1% lower</strong> than pre-pandemic levels.</p>\n  <br>\n  <p><strong>Businesses severely affected:</strong></p>\n  <ul>\n    <li>Travel and tourism</li>\n    <li>Hospitality — pubs, restaurants, cafés</li>\n    <li>Retail (non-essential shops)</li>\n    <li>Entertainment — theatres, cinemas, festivals</li>\n  </ul>\n  <br>\n  <p><strong>Government support measures:</strong></p>\n  <ul>\n    <li>Grants and loans to struggling businesses</li>\n    <li>Furlough scheme — government paid up to 80% of wages for workers who could not work</li>\n  </ul>\n  <br>\n  <p><strong>Businesses that thrived:</strong></p>\n  <ul>\n    <li>Online retailers and delivery companies</li>\n    <li>Home improvement businesses (builders, decorators, home furnishings)</li>\n  </ul>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> Even in the worst economic climate, <strong>some businesses benefit</strong>. The pandemic accelerated the shift to online retail and home working. Businesses that could adapt quickly — or whose products were in demand — survived and grew. The pandemic is a perfect exam example of both the negative <em>and</em> positive effects of an unfavourable economic climate.</p>", "question": "According to this case study, what does the pandemic show about an unfavourable economic climate?", "options": ["Even in a very bad economic climate, some businesses can still benefit", "Every single business in the country closed permanently during the pandemic", "No business anywhere was able to benefit from the pandemic in any way", "GDP rose to its highest ever recorded level during the pandemic period"]}'::jsonb, '{"answer": 0, "explain": "The card explains the pandemic shows even in the worst economic climate some businesses benefit — online retailers and home improvement businesses thrived."}'::jsonb),
('business:6-2-the-economic-climate:learn:21a4e306', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Fitspace — Low-Cost Gym in a Changing Economy", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Fitspace — Targeting Lower-Income Consumers</h4>\n  <p>Fitspace is a gym chain that specifically targets lower-paid workers and those without a guaranteed stable income. It operates as follows:</p>\n  <ul>\n    <li>Monthly membership fees lower than most other gyms</li>\n    <li>No annual contract — customers can pay month by month</li>\n    <li>No frills — no luxury changing rooms, saunas or cafés</li>\n  </ul>\n  <br>\n  <p>In 2016, Fitspace was acquired by GLL (which also runs the Better gym chain). By 2018, GLL''s turnover had grown 7% to £298 million with a profit of £1.3 million.</p>\n</div>\n<br>\n<p><strong>📌 Takeaway:</strong> Fitspace is a prime example of a business that aligned its model to the economic reality of its target market. By keeping costs and prices low, it attracted customers who would otherwise not join a gym. However, its lack of frills may deter customers seeking higher-quality experiences — showing that <strong>every strategy involves trade-offs</strong>.</p>", "question": "According to the Fitspace case study, how did the business align with the economic reality of its market?", "options": ["By requiring customers to sign a long and expensive annual contract term", "By keeping membership costs and prices low to attract lower-income customers", "By adding luxury features such as saunas and cafés to its gyms", "By targeting only the highest-income consumers in each local area"]}'::jsonb, '{"answer": 1, "explain": "The card explains Fitspace kept membership fees low with no annual contract or frills, aligning its model with lower-paid workers and unstable incomes."}'::jsonb),
('business:6-2-the-economic-climate:misc:c3b9dd8c', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The ''economic climate'' is about the weather or environmental climate change.</p><p><strong>✅ The correct idea:</strong> The economic climate refers to the state of income and employment levels in a country — it has nothing to do with weather. The examiner reports note that less than 40% of students answered Q1 correctly because of this confusion.</p>", "question": "What does the term ''economic climate'' actually refer to?", "options": ["The weather conditions affecting a country''s agriculture sector", "The rate of environmental climate change in a country", "The state of income and employment levels in a country", "The number of businesses that operate within a country"]}'::jsonb, '{"answer": 2, "explain": "The card corrects a common misconception — the economic climate refers to income and employment levels, not weather or environmental climate change."}'::jsonb),
('business:6-2-the-economic-climate:misc:6716c390', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If unemployment falls, a business now has fewer employees.</p><p><strong>✅ The correct idea:</strong> A fall in unemployment means there are FEWER unemployed people in the country — not fewer people working for a specific business. It means it becomes HARDER and MORE EXPENSIVE to recruit new workers, as fewer people are available.</p>", "question": "What does a fall in unemployment actually mean for businesses trying to recruit?", "options": ["A specific business now automatically has fewer employees working for it", "It becomes easier and cheaper to recruit, since more people are now available", "Recruitment costs are not affected at all by the unemployment rate", "It becomes harder and more expensive to recruit, as fewer people are available"]}'::jsonb, '{"answer": 3, "explain": "The card explains a fall in unemployment means fewer people are available nationally, making it harder and more expensive for businesses to recruit new workers."}'::jsonb),
('business:6-2-the-economic-climate:misc:5996d7f0', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A fall in consumer income always causes every business to sell less.</p><p><strong>✅ The correct idea:</strong> It depends on the type of product. Luxury goods businesses typically see sales fall. But budget and discount businesses (like Aldi) often see sales RISE as consumers trade down to cheaper options.</p>", "question": "Does a fall in consumer income always cause every business to sell less?", "options": ["No — discount businesses like Aldi can see sales rise as customers trade down", "Yes — every single business always sells less whenever consumer income falls", "No — but only because consumer income never actually falls in reality", "Yes — but only luxury goods businesses are exempt from this effect"]}'::jsonb, '{"answer": 0, "explain": "The card explains it depends on the product type — luxury goods businesses see sales fall, but discount businesses like Aldi often see sales rise as consumers trade down."}'::jsonb),
('business:6-2-the-economic-climate:misc:0648db6f', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Economic factors include things like the cost of raw materials, rents, and prices.</p><p><strong>✅ The correct idea:</strong> Costs, rents, and prices are NOT economic factors in the OCR specification. Economic factors specifically refer to consumer income levels, (un)employment, economic growth/GDP, and inflation. Do not confuse these with business costs.</p>", "question": "According to the OCR specification, which of these counts as an economic factor?", "options": ["The cost of raw materials used in a business''s production process", "Consumer income levels, unemployment, and economic growth or GDP", "The rent a business pays for its premises each and every month", "The prices a business charges its own customers for its products"]}'::jsonb, '{"answer": 1, "explain": "The card explains economic factors specifically mean income, employment, growth/GDP and inflation — not business costs like raw materials, rent or prices."}'::jsonb),
('business:6-2-the-economic-climate:misc:0654efa2', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing about how the economic climate affects business generally — without linking to the specific case study — is enough for full marks on a 3-mark analyse question.</p><p><strong>✅ The correct idea:</strong> You CANNOT score application or analysis marks without first showing understanding. You must also use evidence from the specific business in the question (e.g. the price of a product, number of employees). No context = maximum 1 mark.</p>", "question": "Can writing about the economic climate generally, without the case study, score full marks on a 3-mark analyse question?", "options": ["Yes — application and analysis marks do not require any case study evidence", "Yes — understanding marks are not required for a 3-mark analyse question", "No — without any case study evidence, the maximum score you can get is 1 mark", "No — but only because 3-mark analyse questions do not exist in this topic"]}'::jsonb, '{"answer": 2, "explain": "The card explains you cannot score application or analysis without case study evidence — without context, the maximum score is 1 mark for understanding alone."}'::jsonb),
('business:6-2-the-economic-climate:misc:bebb4c1a', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 3-mark recommend/evaluate question, I just need to explain my chosen option in detail.</p><p><strong>✅ The correct idea:</strong> A 3-mark evaluation question REQUIRES a comparison between both options. If you only justify your chosen option without saying why it is better THAN the other option, you can score a maximum of 1 mark.</p>", "question": "Is explaining your chosen option in detail enough for full marks on a 3-mark recommend question?", "options": ["Yes — a 3-mark recommend question never requires any kind of comparison", "Yes — comparing both options actually loses marks in this question type", "No — but only because recommend questions are always worth more than 3 marks", "No — you must also compare it against the other option to score full marks"]}'::jsonb, '{"answer": 3, "explain": "The card explains a 3-mark evaluation question requires comparing both options — justifying only the chosen option without contrast scores a maximum of 1 mark."}'::jsonb),
('business:6-2-the-economic-climate:misc:616ad3fd', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Inflation, interest rates, and economic growth are outside the scope of this topic.</p><p><strong>✅ The correct idea:</strong> While the OCR specification focuses mainly on income and unemployment for 6.2, examiners WILL accept other valid economic factors (such as inflation and economic growth/GDP) when a question asks for an ''economic factor''. These are credit-worthy answers.</p>", "question": "Are inflation and economic growth completely outside the scope of this topic?", "options": ["No — examiners will accept them as valid economic factors when relevant", "Yes — inflation and economic growth can never be credited in this topic", "Yes — only income and unemployment can ever be mentioned in any answer", "No — but only inflation is accepted, never economic growth or GDP"]}'::jsonb, '{"answer": 0, "explain": "The card explains that while 6.2 focuses mainly on income and unemployment, examiners will accept other valid economic factors like inflation and GDP when relevant."}'::jsonb),
('business:6-2-the-economic-climate:misc:2848f641', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The economic climate only affects large businesses — small businesses are too small to be impacted.</p><p><strong>✅ The correct idea:</strong> The economic climate affects businesses of ALL sizes. A small independent café may be more vulnerable than a large chain because it has fewer reserves. Small businesses are frequently used as case studies in this topic.</p>", "question": "Does the economic climate only affect large businesses, not small ones?", "options": ["Yes — small businesses are too small to ever be affected by the economy", "No — it affects businesses of all sizes, and small ones may be more vulnerable", "Yes — only large multinational businesses are ever used as exam case studies", "No — but only because small businesses always have larger cash reserves"]}'::jsonb, '{"answer": 1, "explain": "The card explains the economic climate affects businesses of all sizes — a small independent café may be more vulnerable than a large chain due to fewer reserves."}'::jsonb),
('business:6-2-the-economic-climate:tips:397dac5d', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Always Define the Economic Problem FIRST", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs two things: a feature of the difficult economic climate (1 mark) AND how it affects the business (1 mark).</p>\n      <br>\n      <p><strong>⚠️ Examiner Warning:</strong> In the real exam, fewer than 40% of students scored any marks on this question type because they jumped straight to the business impact without defining what a difficult economic climate actually involves.</p>\n      <br>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 (K):</strong> Identify a feature of a difficult economic climate (e.g. rising unemployment OR falling consumer incomes)</li>\n        <li><strong>Step 2 (U):</strong> Explain how this affects the business (e.g. demand may fall, sales may decrease)</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br>\n      <em>\"The economic climate is changing and this affects businesses.\"</em><br>\n      This shows no understanding of what a difficult economic climate IS.</p>\n      <br>\n      <p><strong>✅ Good Answer (2 marks):</strong><br>\n      <em>\"In a difficult economic climate, unemployment may rise (K). This means consumers have less income to spend, so demand for the business''s products may fall (U).\"</em></p>\n      <br>\n      <p><strong>🚫 Misconception Alert:</strong> The economic climate does NOT refer to weather or environmental change. Always connect it to income and/or unemployment.</p>\n    ", "question": "According to this card, why did fewer than 40% of students score marks on this question type?", "options": ["They defined the economic climate but never mentioned any business impact at all", "They wrote far too much detail for a question that was only worth two marks", "They jumped straight to the business impact without defining the economic climate", "They confused this two-mark question with a much longer nine-mark essay question"]}'::jsonb, '{"answer": 2, "explain": "The card explains most students jumped straight to the business impact without first defining what a difficult economic climate actually involves, losing the knowledge mark."}'::jsonb),
('business:6-2-the-economic-climate:tips:df838f30', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>Every 3-mark <strong>analyse</strong> question follows the same structure. Miss the understanding step and you score ZERO — even if your application and analysis are perfect.</p>\n      <br>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State what the economic concept means (e.g. \"A fall in consumer income means customers have less money to spend.\")</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link directly to the specific business in the case study using a fact or figure (e.g. \"GK''s kitchens are priced at £15,000...\")</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line impact on the business (e.g. \"...so demand for GK''s kitchens is likely to fall, meaning they may not reach their break-even point of 29 units.\")</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (1 mark maximum):</strong><br>\n      <em>\"GK will sell fewer kitchens because incomes are falling.\"</em><br>\n      No understanding shown — skipped straight to the impact.</p>\n      <br>\n      <p><strong>✅ Good Answer (3 marks):</strong><br>\n      <em>\"A fall in consumer income means customers have less money to spend (U). As GK''s Deluxe kitchen costs £15,000 (APP), it is likely that fewer customers will be able to afford this luxury purchase, causing sales to fall. This may mean GK fails to reach its break-even point of 29 kitchens (AN).\"</em></p>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(U):</em> \"A fall in consumer income means that customers have less disposable income to spend...\"</li>\n        <li><em>(APP):</em> \"In the case of [business], which sells [product/price from text]...\"</li>\n        <li><em>(AN):</em> \"This will lead to... / As a result, the business will... / This means profits may fall because...\"</li>\n      </ul>\n    ", "question": "According to this card, what happens if you skip the Understanding step in a 3-mark analyse question?", "options": ["You still score full marks, since application matters more than understanding", "You automatically score 2 out of 3 marks for the remaining two steps", "You score full marks provided your final numerical answer is correct", "You score zero, even if your application and analysis are perfect"]}'::jsonb, '{"answer": 3, "explain": "The card warns that missing the understanding step scores zero overall, even with perfect application and analysis — understanding is the required first step."}'::jsonb),
('business:6-2-the-economic-climate:tips:95f8a522', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tips', 'mcq', 1, '{"readingTitle": "Recommend / Evaluate — 3 marks — You MUST Compare Both Options", "reading": "\n      <p>A 3-mark <strong>recommend</strong> question is the most commonly under-scored question. Students lose marks because they argue for their chosen option but <strong>never say why it is better than the other option</strong>.</p>\n      <br>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Judgement (1 mark):</strong> State your clear decision (e.g. \"The fall in consumer income will have the greater impact...\")</li>\n        <li><strong>Step 2 — Justification with contrast (1 mark):</strong> Explain WHY your choice is bigger/more important THAN the other factor</li>\n        <li><strong>Step 3 — Context (1 mark):</strong> Use a specific figure or detail from the case study to support your comparison</li>\n      </ul>\n      <br>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br>\n      <em>\"Consumer income will have the greatest impact because people will have less money to spend on kitchens.\"</em><br>\n      A judgement with justification — but no comparison to the unemployment factor.</p>\n      <br>\n      <p><strong>✅ Good Answer (3 marks):</strong><br>\n      <em>\"The fall in consumer income will have the greater impact on GK (JUDGEMENT). Although unemployment is forecast to fall by 0.9%, newly employed people are unlikely to immediately purchase a £15,000 luxury kitchen (CONTEXT + CONTRAST). In contrast, falling consumer income directly reduces the spending power of GK''s existing customer base, making it much harder for GK to achieve its break-even of 29 kitchens (JUSTIFICATION).\"</em></p>\n      <br>\n      <p><strong>⚠️ Examiner Warning:</strong> If you do not compare both factors, you can score a maximum of 1 mark on a 3-mark evaluation question — regardless of how detailed your answer is.</p>\n    ", "question": "According to this card, what is the maximum score if you don''t compare both options?", "options": ["1 mark, regardless of how detailed your chosen-option answer actually is", "3 marks, since a detailed justification alone is enough for full credit", "0 marks, since any answer without a comparison scores absolutely nothing", "2 marks, since justification and context are still both clearly present"]}'::jsonb, '{"answer": 0, "explain": "The card explains you can score a maximum of 1 mark without comparing both options — regardless of how detailed your justification of the chosen option is."}'::jsonb),
('business:6-2-the-economic-climate:tips:30788d01', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Two Stakeholders: Analyse, Then Judge", "reading": "\n      <p>The 7-mark evaluate question requires you to discuss the impact on <strong>two different stakeholders</strong> and then make a final judgement about which is more affected.</p>\n      <br>\n      <p><strong>Structure — 3 Paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — Stakeholder 1 (APP + AN):</strong> Identify stakeholder 1, apply the economic change to them using the case study, and analyse the impact on them specifically.</li>\n        <li><strong>Paragraph 2 — Stakeholder 2 (APP + AN):</strong> Repeat for a different stakeholder — use different impacts to avoid repetition.</li>\n        <li><strong>Paragraph 3 — Evaluation (EVAL × 3):</strong> Make a decision + state context + explain why this stakeholder is MORE affected than the other.</li>\n      </ul>\n      <br>\n      <p><strong>Good stakeholder choices for a rise in unemployment:</strong></p>\n      <ul>\n        <li>Customers — less income to spend, forced to buy cheaper goods</li>\n        <li>Shareholders — lower profits may reduce dividends and share price</li>\n        <li>Employees — risk of redundancy, pressure to accept lower wages</li>\n        <li>Suppliers — orders may fall if the business reduces production</li>\n      </ul>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(APP P1):</em> \"Customers of Tesco plc would be affected because a rise in unemployment means...\"</li>\n        <li><em>(AN P1):</em> \"As a result, customers may need to switch to cheaper product ranges, reducing their quality of life...\"</li>\n        <li><em>(APP P2):</em> \"Shareholders may also be impacted because falling sales lead to lower profits...\"</li>\n        <li><em>(EVAL):</em> \"Overall, I believe customers are more affected than shareholders because... However, this depends on whether Tesco''s product range (from ''basics'' to ''finest'') allows it to retain customers even during a downturn...\"</li>\n      </ul>\n    ", "question": "According to this card, what must a 7-mark evaluate answer discuss?", "options": ["The impact on only one single stakeholder, in as much detail as possible", "The impact on two different stakeholders, followed by a final judgement", "A calculation showing the exact numerical impact on the business''s profit", "A definition of the economic climate with no further analysis at all"]}'::jsonb, '{"answer": 1, "explain": "The card requires discussing the impact on two different stakeholders in separate paragraphs, then a final judgement on which is more affected."}'::jsonb),
('business:6-2-the-economic-climate:tips:4c6c83e2', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — The Full Essay: Knowledge → Analysis → Evaluation", "reading": "\n      <p>The 9-mark question is the highest-tariff question in this topic. It requires <strong>knowledge, application, analysis from two angles, and a fully justified conclusion</strong>.</p>\n      <br>\n      <p><strong>Structure — 4 Paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Define the key economic concept and explain how it generally affects businesses.</li>\n        <li><strong>Paragraph 2 — AN &amp; APP (Impact 1):</strong> Analyse one specific impact on the named business, using evidence from the case study.</li>\n        <li><strong>Paragraph 3 — AN &amp; APP (Impact 2):</strong> Analyse a second, different impact (e.g. the marketing response, or the effect on a different area like HR or Finance).</li>\n        <li><strong>Paragraph 4 — Evaluation (3 points):</strong>\n          <ul>\n            <li><strong>Decision:</strong> State your overall judgement (e.g. \"Overall, a fall in consumer income is the greater threat to NEXT...\")</li>\n            <li><strong>Context:</strong> Refer to a specific detail from the case study to support your conclusion</li>\n            <li><strong>Impact/Reasoning:</strong> Explain why — include a counterargument or limiting factor (e.g. \"However, this depends on whether NEXT can successfully reposition itself as a value-for-money brand...\")</li>\n          </ul>\n        </li>\n      </ul>\n      <br>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about the economic climate. Every sentence must link back to the specific business in the question. Generic statements about recessions score very few marks at Level 3.</p>\n      <br>\n      <p><strong>📝 Sentence Starters:</strong></p>\n      <ul>\n        <li><em>(K/U):</em> \"A fall in consumer income means customers have less disposable income available to spend...\"</li>\n        <li><em>(AN/APP P2):</em> \"For NEXT plc, which sells clothing and accessories, this is particularly significant because...\"</li>\n        <li><em>(AN/APP P3):</em> \"NEXT''s marketing department may need to respond by... This could involve changing the 4Ps, specifically...\"</li>\n        <li><em>(EVAL — Decision):</em> \"Overall, I believe that a fall in consumer income poses the greater threat to NEXT''s marketing activities...\"</li>\n        <li><em>(EVAL — Context):</em> \"This is because NEXT operates in a competitive market where customers can easily switch to cheaper rivals such as Primark...\"</li>\n        <li><em>(EVAL — Reasoning):</em> \"However, the impact depends on how quickly NEXT adapts its pricing strategy and whether it can maintain brand loyalty during a period of falling incomes...\"</li>\n      </ul>\n    ", "question": "According to this card, what does the 9-mark question require beyond analysis from two angles?", "options": ["Nothing further — analysis from two angles alone is enough for full marks", "A comparison with a completely different exam topic entirely", "Knowledge, application, and a fully justified conclusion", "A hand-drawn diagram illustrating the economic concept being discussed"]}'::jsonb, '{"answer": 2, "explain": "The card explains the 9-mark question requires knowledge, application, analysis from two angles AND a fully justified conclusion in the final paragraph."}'::jsonb),
